const resp = $input.first().json;
const items = resp.leads || [];
if (items.length === 0) {
  return [{ json: { _empty: true, count: 0 } }];
}
return items.map(item => ({ json: item }));

const items = $input.all();

function normEmail(e) {
  if (!e || typeof e !== 'string') return null;
  return e.trim().toLowerCase();
}

function normDomain(d) {
  if (!d || typeof d !== 'string') return null;
  let v = d.trim().toLowerCase();
  v = v.replace(/^https?:\/\//, '').replace(/^www\./, '');
  v = v.split('/')[0].split('?')[0].split('#')[0];
  v = v.replace(/:\d+$/, '');
  return (v && v.includes('.')) ? v : null;
}

function isValidEmail(e) {
  return /^[a-z0-9._%+\-]+@[a-z0-9.\-]+\.[a-z]{2,}$/.test(e);
}

const results = [];

for (const item of items) {
  const r = item.json;
  const email = normEmail(r.email);
  const domain = normDomain(r.domain);
  const bizName = (r.business_name || '').trim();

  const missing = [];
  if (!email) missing.push('email');
  if (!domain) missing.push('domain');
  if (!isValidEmail(email || '')) missing.push('email_format');
  if (!r.id) missing.push('id');
  if (!bizName) missing.push('business_name');

  const valid = missing.length === 0;

  results.push({
    json: {
      id: r.id, business_name: bizName, website: r.website || null,
      domain, email, email_status: r.email_status, lead_status: r.lead_status,
      outreach_status: r.outreach_status, export_status: r.export_status,
      smartlead_status: r.smartlead_status,
      needs_manual_review: r.needs_manual_review || false,
      created_at: r.created_at, updated_at: r.updated_at,
      _valid: valid, _missing_fields: missing,
      _norm_email: email, _norm_domain: domain,
      _norm_biz: bizName.toLowerCase().replace(/[^a-z0-9]/g, '')
    }
  });
}

return results;

const items = $input.all();

const valid = [];
const blocked = [];

for (const item of items) {
  const r = item.json;
  if (!r._valid) {
    blocked.push({ ...r, export_decision: 'blocked', smartlead_decision: 'not_exportable', review_decision: true, decision_reason: 'missing_fields:' + (r._missing_fields || []).join(',') });
  } else {
    valid.push(r);
  }
}

const byEmail = new Map();
for (const r of valid) {
  const key = r._norm_email;
  if (!byEmail.has(key)) byEmail.set(key, []);
  byEmail.get(key).push(r);
}

function pickWinner(rows) {
  return rows.sort((a, b) => {
    const aV = a.email_status === 'verified' ? 1 : 0;
    const bV = b.email_status === 'verified' ? 1 : 0;
    if (bV !== aV) return bV - aV;
    const aB = a.business_name ? 1 : 0;
    const bB = b.business_name ? 1 : 0;
    if (bB !== aB) return bB - aB;
    return new Date(a.created_at || 0).getTime() - new Date(b.created_at || 0).getTime();
  })[0];
}

const emailWinners = new Map();
const emailDupes = [];

for (const [email, rows] of byEmail) {
  if (rows.length === 1) {
    emailWinners.set(rows[0].id, rows[0]);
  } else {
    const winner = pickWinner([...rows]);
    emailWinners.set(winner.id, winner);
    for (const r of rows) {
      if (r.id !== winner.id) {
        emailDupes.push({ ...r, export_decision: 'duplicate', smartlead_decision: 'not_exportable', review_decision: true, decision_reason: 'email_duplicate_of:' + winner.id });
      }
    }
  }
}

const byDomain = new Map();
for (const [id, r] of emailWinners) {
  const key = r._norm_domain;
  if (!byDomain.has(key)) byDomain.set(key, []);
  byDomain.get(key).push(r);
}

function isObviousDuplicate(a, b) {
  if (!a || !b) return false;
  if (a === b) return true;
  if (a.includes(b) && b.length >= 3) return true;
  if (b.includes(a) && a.length >= 3) return true;
  return false;
}

const domainDupes = [];
const winners = new Map();

for (const [domain, rows] of byDomain) {
  if (rows.length === 1) { winners.set(rows[0].id, rows[0]); continue; }
  const groups = [];
  const assigned = new Set();
  for (let i = 0; i < rows.length; i++) {
    if (assigned.has(i)) continue;
    const group = [rows[i]];
    assigned.add(i);
    for (let j = i + 1; j < rows.length; j++) {
      if (assigned.has(j)) continue;
      if (isObviousDuplicate(rows[i]._norm_biz, rows[j]._norm_biz)) {
        group.push(rows[j]); assigned.add(j);
      }
    }
    groups.push(group);
  }
  for (const group of groups) {
    if (group.length === 1) { winners.set(group[0].id, group[0]); }
    else {
      const winner = pickWinner([...group]);
      winners.set(winner.id, winner);
      for (const r of group) {
        if (r.id !== winner.id) {
          domainDupes.push({ ...r, export_decision: 'duplicate', smartlead_decision: 'not_exportable', review_decision: true, decision_reason: 'domain_duplicate_of:' + winner.id });
        }
      }
    }
  }
}

const ready = [];
for (const [id, r] of winners) {
  const isRisky = r.email_status === 'risky';
  ready.push({ ...r, export_decision: 'ready', smartlead_decision: 'pending_export', review_decision: isRisky ? true : r.needs_manual_review, decision_reason: isRisky ? 'risky_email' : 'clean' });
}

return [...ready, ...blocked, ...emailDupes, ...domainDupes].map(r => ({ json: r }));

const items = $input.all();
const decisions = items.map(item => ({
  id: item.json.id,
  export_decision: item.json.export_decision,
  smartlead_decision: item.json.smartlead_decision,
  review_decision: item.json.review_decision
}));

return [{ json: { decisions, count: decisions.length } }];

const apiResp = $input.first().json;

return [{
  json: {
    _type: 'summary',
    total_decisions: apiResp.total_decisions || 0,
    db_updated: apiResp.db_updated || 0,
    db_skipped: apiResp.db_skipped || 0,
    ready_for_export: apiResp.ready_for_export || 0,
    blocked: apiResp.blocked || 0,
    duplicates: apiResp.duplicates || 0,
    rows: apiResp.rows || []
  }
}];
